import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XSSFixedCode {

    public void processUserInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Sanitize and encode user input before using it
        String sanitizedInput = sanitizeInput(userInput);
        String encodedOutput = "<p>User Input: " + sanitizedInput + "</p>";

        // Sending the output back in the response after encoding
        response.setContentType("text/html");
        response.getWriter().write(encodedOutput);
    }

    private String sanitizeInput(String input) {
        // Implement proper input sanitization logic here (e.g., HTML escaping)
        return input == null ? "" : input.replaceAll("<", "&lt;").replaceAll(">", "&gt;");
    }
}

